// Script: generar_40_revertir_bloqueo_scroll.js
// Que hace: REVIERTE el hook useBloquearScroll (de los scripts 38 y 39),
// ya que en vez de arreglar el problema del menu cortado lo empeoro,
// extendiendolo a otras pantallas (registros, observaciones,
// enfermedades) donde antes SI se podia guardar normalmente.
//
// Vuelve al estado de antes de ese intento: los modales tienen
// "max-h-[90vh] overflow-y-auto" (el fix simple que aplicamos primero),
// SIN el bloqueo de scroll del body que causo el problema mas grande.
//
// El bug original (menu de editar/eliminar cortado en tarjetas al final
// de la lista) puede seguir presente, pero es preferible a tener TODOS
// los formularios de guardado rotos.
//
//   1) app/prevencion/page.tsx
//   2) app/registro-diario/page.tsx
//   3) components/PesoTracker.tsx
//
// IMPORTANTE: este script no borra utils/useBloquearScroll.ts (el
// archivo queda ahi sin usarse, no genera ningun problema dejarlo).
//
// Como correrlo: node generar_40_revertir_bloqueo_scroll.js
// Confirma "OK" para los 3 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/prevencion/page.tsx', "");
escribir('app/registro-diario/page.tsx', "");
escribir('components/PesoTracker.tsx', "");
